fun solve(grid: Array<Array<Long>>, x: Long, y: Long, k: Long): Array<Array<Long>> {
    val m = grid.size
    val n = grid[0].size
    val result = Array(m) { Array(n) { 0L } }

    // Copy the parts of the matrix that are not in the submatrix
    for (i in 0 until m) {
        for (j in 0 until n) {
            if (i < x || i >= x + k || j < y || j >= y + k) {
                result[i][j] = grid[i][j]
            }
        }
    }

    // Flip the submatrix vertically
    for (i in 0 until k) {
        for (j in 0 until n) {
            val row = x + k - 1 - i
            result[row][j] = grid[x + i][j]
        }
    }

    return result
}
